/**
 * Prompt Expansion Observer
 * Hook: UserPromptExpansion (CC 2.1.208)
 *
 * Fires when a typed /command expands, BEFORE the model sees it. The event
 * CAN block, but this hook is an OBSERVER ONLY (P3-A3): it never blocks and
 * never modifies the expansion — it emits one compact telemetry line so we
 * learn the real payload shape and expansion frequency in the wild.
 *
 * Input is UNTRUSTED and the payload shape is unverified against live CC:
 * every field is read defensively and logged sizes are capped. The raw
 * prompt/expansion text is NEVER logged (may contain secrets) — only the
 * leading /command token (sanitized) and length metrics.
 */

import type { HookInput, HookResult, HookContext } from '../types.js';
import { outputSilentSuccess, logHook } from '../lib/common.js';
import { NOOP_CTX } from '../lib/context.js';

const HOOK_NAME = 'prompt/prompt-expansion-observer';

/** Max chars of the /command token we ever log. */
const MAX_TOKEN_LEN = 64;

/** Read a string field off untrusted input; empty string when absent/non-string. */
function str(input: HookInput, key: string): string {
  const v = (input as unknown as Record<string, unknown>)[key];
  return typeof v === 'string' ? v : '';
}

/**
 * Extract the leading /command token from an untrusted prompt string.
 * Strips control chars, allows only slash-command-safe chars, caps length.
 */
function commandToken(prompt: string): string {
  if (!prompt.startsWith('/')) return '';
  const firstWord = prompt.slice(0, 256).split(/\s/, 1)[0] ?? '';
  const clean = firstWord.replace(/[^\w:/-]/g, '');
  return clean.slice(0, MAX_TOKEN_LEN);
}

export async function promptExpansionObserver(
  input: HookInput,
  _ctx: HookContext = NOOP_CTX,
): Promise<HookResult> {
  try {
    // Candidate fields across plausible payload shapes — all optional.
    const prompt = str(input, 'prompt');
    const expanded =
      str(input, 'expanded_prompt') || str(input, 'expansion') || str(input, 'expanded');
    const command = commandToken(str(input, 'command') || prompt);

    logHook(
      HOOK_NAME,
      `expansion observed cmd=${command || '(none)'} prompt_len=${prompt.length} expanded_len=${expanded.length}`,
      'info',
    );
  } catch {
    // Observer only — never let telemetry failures surface to CC
  }
  return outputSilentSuccess();
}
